			=> AsyncOperation.FromTask(ct =>
			{
				if (uri.IsAppData())
				{
					return Task.FromResult(GetFileFromPath(AppDataUriEvaluator.ToPath(uri)));
				}

				return GetFileFromApplicationUri(ct, uri);
			});

